SELECT id, metric_type, metric_name, metric_value, metric_unit, collect_time, create_time
FROM sys_monitor_history
WHERE metric_type = #{metricType}
  AND collect_time BETWEEN #{startTime} AND #{endTime}
ORDER BY collect_time ASC

